import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const f=JSON.parse('{"title":"Defaultエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"ナビゲーション、システム制御、日常タスクのための必須シェルエイリアス。これらのユニバーサルショートカットでターミナルワークフローを簡素化。","frontmatter":{"title":"Defaultエイリアス | Dotfiles","description":"ナビゲーション、システム制御、日常タスクのための必須シェルエイリアス。これらのユニバーサルショートカットでターミナルワークフローを簡素化。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Defaultエイリアス preview","canonical":"/ja/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Defaultエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"Defaultエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"default aliases, shell aliases, terminal shortcuts, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Defaultエイリアス - Dotfiles"},{"name":"twitter:description","content":"ナビゲーション、システム制御、日常タスクのための必須シェルエイリアス。"},{"name":"og:title","content":"Defaultエイリアス - Dotfiles"},{"name":"og:description","content":"ナビゲーション、システム制御、日常タスクのための必須シェルエイリアス。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/default/index.md","filePath":"ja/aliases/default/index.md","lastUpdated":1773010926000}'),c={name:"ja/aliases/default/index.md"};function r(i,t,l,h,n,s){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="defaultエイリアス" tabindex="-1">Defaultエイリアス <a class="header-anchor" href="#defaultエイリアス" aria-label="Permalink to &quot;Defaultエイリアス&quot;">​</a></h1><p>日常のターミナルタスクのための必須シェルショートカット。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>デフォルトエイリアスは、一般的なターミナル操作を効率化するユニバーサルシェルショートカットのコレクションを提供します。これらのエイリアスは<code>default.aliases.sh</code>で定義され、chezmoiによってサポートされるすべてのシェルで自動的にロードされます。</p><p>これらのショートカットは、一般ユーティリティ、終了コマンド、ネットワーク診断、システム監視、ファイルシステムナビゲーションをカバーしています。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="一般" tabindex="-1">一般 <a class="header-anchor" href="#一般" aria-label="Permalink to &quot;一般&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>現在の日付と時刻を表示</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>作業ディレクトリを表示</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>PATH変数を改行で表示</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>シェルをリロード</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>ファイル出力をリアルタイムで追跡</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>現在の週番号を表示</td></tr></tbody></table><h3 id="終了とシャットダウン" tabindex="-1">終了とシャットダウン <a class="header-anchor" href="#終了とシャットダウン" aria-label="Permalink to &quot;終了とシャットダウン&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>シェルを終了</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>シェルを終了</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>シェルを終了</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>シェルを終了（vimスタイル）</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>システムを停止</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>システムの電源を切る</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>システムを再起動</td></tr></tbody></table><h3 id="履歴" tabindex="-1">履歴 <a class="header-anchor" href="#履歴" aria-label="Permalink to &quot;履歴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>コマンド履歴を表示</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>ISO 8601タイムスタンプ付きで履歴を表示</td></tr></tbody></table><h3 id="ネットワーク" tabindex="-1">ネットワーク <a class="header-anchor" href="#ネットワーク" aria-label="Permalink to &quot;ネットワーク&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>ネットワークインターフェースを設定</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>en0のネットワークパラメータを取得</td></tr><tr><td><code>nls</code></td><td><code>sudo lsof -i -P | grep LISTEN</code></td><td>アクティブなネットワークリスナーを表示</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>開いているポートを一覧表示</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>5パケット制限でping</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>すべてのリスニングポートを一覧表示</td></tr></tbody></table><h3 id="システム監視" tabindex="-1">システム監視 <a class="header-anchor" href="#システム監視" aria-label="Permalink to &quot;システム監視&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>インタラクティブプロセスモニター</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>ASLログファイルをクリア</td></tr></tbody></table><h3 id="ユーティリティ" tabindex="-1">ユーティリティ <a class="header-anchor" href="#ユーティリティ" aria-label="Permalink to &quot;ユーティリティ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>ctf</code></td><td><code>ls -1 | wc -l</code></td><td>現在のディレクトリのファイル数をカウント</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>クイックファイル検索</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>シェルをリロード</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>現在の天気を取得</td></tr></tbody></table>',18)])])}const b=d(c,[["render",r]]);export{f as __pageData,b as default};
